SELECT EXISTS(
    SELECT 1
      FROM com.tc_com_cd_dtl
     WHERE grp_id = #{grpId}
       AND cd     = #{cd}
       AND NOW() BETWEEN use_bgng_dt AND use_end_dt
)

SELECT grp_id, cd, cd_nm, cd_desc, cd_ord, cd_attr_1, cd_attr_2, cd_attr_3,
       use_bgng_dt, use_end_dt, frst_reg_dt, frst_reg_user_id, last_chg_dt, last_chg_user_id
  FROM com.tc_com_cd_dtl
 WHERE grp_id = #{grpId}
   AND cd     = #{cd}
   AND NOW() BETWEEN use_bgng_dt AND use_end_dt

