UPDATE com.tc_com_cd_group
   SET use_end_dt = NOW() - INTERVAL '1 minute',
       last_chg_dt = NOW(),
       last_chg_user_id = #{userId}
 WHERE grp_id = #{grpId}
   AND NOW() BETWEEN use_bgng_dt AND use_end_dt

UPDATE com.tc_com_cd_dtl
   SET use_end_dt = NOW() - INTERVAL '1 minute',
       last_chg_dt = NOW(),
       last_chg_user_id = #{userId}
 WHERE grp_id = #{grpId}
   AND cd     = #{cd}
   AND NOW() BETWEEN use_bgng_dt AND use_end_dt
